/**
 * Parse Gemini Response / Parse Tool Call
 *
 * Option D : Gemini function calling pattern.
 *
 * Détecte si Gemini veut appeler une fonction (get_available_slots) ou a directement
 * répondu en texte. Route ensuite via le node Has Tool Call?.
 *
 * Guardrail : Gemini 2.5 Flash Lite a un biais tool-use et appelle parfois la fonction
 * même pour des salutations simples. On override via regex pour économiser tokens
 * (2e appel + RPC) et garantir une UX cohérente.
 */
const geminiOutput = $input.first().json;
const candidate = geminiOutput.candidates?.[0];
const parts = candidate?.content?.parts || [];
const usageMetadata = geminiOutput.usageMetadata || {};

// Cherche un functionCall dans les parts
const fnCallPart = parts.find(p => p.functionCall);
const fnCall = fnCallPart?.functionCall;
const textPart = parts.find(p => p.text !== undefined)?.text;

const ctx = $('Compute Budget Status').first().json;

// --- Guardrail greetings ---
// Si l'utilisateur a juste dit Bonjour/Merci/etc., on écrase l'éventuel tool call
// de Gemini et on retourne une réponse texte directe.
const GREETING_PATTERN = /^(bonjour|coucou|salut|hello|bonsoir|hi|hey|yo|hola|allo|allô|cc)[!.\s,]*$/i;
const THANKS_PATTERN = /^(merci|thanks|thx|ok|d'accord|daccord|parfait|super)[!.\s,]*$/i;
const msgText = String(ctx.safe_message_text || '').trim();
const isGreeting = GREETING_PATTERN.test(msgText);
const isThanks = THANKS_PATTERN.test(msgText);

if (fnCall && (isGreeting || isThanks)) {
  // Override : Gemini voulait appeler la fonction pour une salutation/remerciement — on ignore
  const aiName = ctx.ai_name || 'AurA';
  const salonName = ctx.salon_name || 'notre salon';
  const overrideText = isGreeting
    ? `Bonjour ! Je suis ${aiName}, l'assistant du salon ${salonName}. Souhaitez-vous prendre rendez-vous ? Dites-moi quel jour vous arrangerait.`
    : `Avec plaisir ! À bientôt au salon ${salonName}.`;

  return [{
    json: {
      ...ctx,
      has_tool_call: false,
      response_text: overrideText,
      action: 'none',
      booking_data: {},
      llm_provider: 'gemini',
      llm_model: 'gemini-2.5-flash-lite',
      llm_prompt_tokens: usageMetadata.promptTokenCount || 0,
      llm_completion_tokens: usageMetadata.candidatesTokenCount || 0,
      llm_total_tokens: usageMetadata.totalTokenCount || 0,
      llm_is_fallback: false,
      llm_error: 'greeting_override'
    }
  }];
}

if (fnCall) {
  // Gemini veut appeler une fonction
  return [{
    json: {
      ...ctx,
      has_tool_call: true,
      tool_name: fnCall.name,
      tool_args: fnCall.args || {},
      tool_call_id: fnCall.id || null,
      conversation_parts: parts,
      gemini_call1_prompt_tokens: usageMetadata.promptTokenCount || 0,
      gemini_call1_completion_tokens: usageMetadata.candidatesTokenCount || 0,
      gemini_call1_total_tokens: usageMetadata.totalTokenCount || 0
    }
  }];
}

// Pas de tool call : réponse texte directe
let parsed;
try {
  parsed = JSON.parse(textPart || '{}');
} catch (e) {
  parsed = {
    response_text: textPart || "Désolé, je n'ai pas compris. Pouvez-vous reformuler ?",
    action: 'none',
    booking_data: {}
  };
}

return [{
  json: {
    ...ctx,
    has_tool_call: false,
    response_text: parsed.response_text || textPart || '',
    action: parsed.action || 'none',
    booking_data: parsed.booking_data || {},
    llm_provider: 'gemini',
    llm_model: 'gemini-2.5-flash-lite',
    llm_prompt_tokens: usageMetadata.promptTokenCount || 0,
    llm_completion_tokens: usageMetadata.candidatesTokenCount || 0,
    llm_total_tokens: usageMetadata.totalTokenCount || 0,
    llm_is_fallback: false,
    llm_error: null
  }
}];

