/**
 * Parse Mistral Response — extrait la réponse + les tokens consommés
 */
const mistralOutput = $input.first().json;
const choice = mistralOutput.choices?.[0];
const usage = mistralOutput.usage || {};

let parsed;
try {
  const text = choice?.message?.content || '{}';
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    response_text: choice?.message?.content || 'Désolé, je n\'ai pas compris. Pouvez-vous reformuler ?',
    action: 'none',
    booking_data: {}
  };
}

return [{
  json: {
    ...$('Compute Budget Status').first().json,
    response_text: parsed.response_text,
    action: parsed.action || 'none',
    booking_data: parsed.booking_data || {},
    // Token tracking
    llm_provider: 'mistral',
    llm_model: 'mistral-small-latest',
    llm_prompt_tokens: usage.prompt_tokens || 0,
    llm_completion_tokens: usage.completion_tokens || 0,
    llm_total_tokens: usage.total_tokens || 0,
    llm_is_fallback: true,
    llm_error: null
  }
}];

/**
 * Static Fallback — message prédéfini quand les 2 LLMs sont down ou budget épuisé
 */
const context = $('Compute Budget Status').first().json;
const budgetExceeded = context.ai_budget_exceeded;

let message;
if (budgetExceeded) {
  message = 'Bonjour ! Notre assistant est temporairement indisponible. ' +
    'Veuillez nous contacter directement par téléphone pour prendre rendez-vous. ' +
    'Nous nous excusons pour la gêne occasionnée.';
} else {
  message = 'Bonjour ! Notre assistant rencontre un problème technique. ' +
    'Un conseiller vous recontactera dans les plus brefs délais. ' +
    'Nous nous excusons pour la gêne occasionnée.';
}

return [{
  json: {
    ...context,
    response_text: message,
    action: 'none',
    booking_data: {},
    // Token tracking
    llm_provider: 'static',
    llm_model: 'static-fallback',
    llm_prompt_tokens: 0,
    llm_completion_tokens: 0,
    llm_total_tokens: 0,
    llm_is_fallback: true,
    llm_error: budgetExceeded ? 'budget_exceeded' : 'both_llms_down'
  }
}];

/**
 * Build Context — flatten webhook + merchant + client into a single object
 * for downstream nodes (Sanitize, Check Budget, AI prompt, etc.)
 */
const wh = $('Webhook Trigger').first().json;
const body = wh.body || wh;

const merchantArr = $('Find Merchant').first().json;
const merchant = (Array.isArray(merchantArr) && merchantArr.length > 0) ? merchantArr[0] : (merchantArr || {});

const clientResp = $('Identify Client').first().json;
const client = Array.isArray(clientResp) && clientResp.length > 0
  ? clientResp[0]
  : (clientResp && clientResp.id ? clientResp : {});

return [{
  json: {
    // From Webhook payload
    channel: body.channel || 'whatsapp',
    sender_id: body.sender_phone || body.sender_id,
    sender_name: body.sender_name,
    message_text: body.message_text || '',
    wa_message_id: body.wa_message_id,
    wa_phone_number_id: body.wa_phone_number_id,
    timestamp: body.timestamp,

    // From Find Merchant
    merchant_id: merchant.id,
    salon_name: merchant.name || 'Salon',
    ai_name: merchant.ai_name || 'AurA',
    ai_tone: merchant.ai_tone || 'friendly',
    ai_languages: merchant.ai_languages || ['fr'],
    preferred_language: (merchant.ai_languages && merchant.ai_languages[0]) || 'fr',
    cancellation_delay_minutes: merchant.cancellation_delay_minutes || 120,
    opening_hours: merchant.opening_hours || {},
    ai_monthly_token_budget: merchant.ai_monthly_token_budget || 100000,
    ai_alert_email: merchant.ai_alert_email || null,

    // From Identify Client (upsert result)
    client_id: client.id,
    client_name: client.name || body.sender_name || 'Inconnu',
    loyalty_points: client.loyalty_points || 0,
    preferred_service: client.preferred_service_id || 'aucun',
    preferred_practitioner: client.preferred_practitioner_id || 'aucun',

    // Placeholders (filled by downstream nodes)
    conversation_id: null,
    conversation_history: 'Premiere interaction',
    available_slots_text: 'Aucun creneau charge'
  }
}];

/**
 * Compute Budget Status — agrège merchant budget + usage du mois
 */
const sanitized = $('Sanitize Prompt Inputs').first().json;

const merchantData = $('Get Merchant Budget').first().json;
const merchant = (Array.isArray(merchantData) && merchantData.length > 0) ? merchantData[0] : {};

const usageData = $('Get Monthly Token Usage').first().json;
const usageRows = Array.isArray(usageData) ? usageData : [];

const budget = merchant.ai_monthly_token_budget || 100000;
const alertEmail = merchant.ai_alert_email || null;
const totalUsed = usageRows.reduce((sum, r) => sum + (r.total_tokens || 0), 0);
const usagePercent = budget > 0 ? Math.round((totalUsed / budget) * 100) : 0;
const budgetExceeded = totalUsed >= budget;

return [{
  json: {
    ...sanitized,
    ai_budget: budget,
    ai_alert_email: alertEmail,
    ai_used_tokens: totalUsed,
    ai_usage_percent: usagePercent,
    ai_budget_exceeded: budgetExceeded
  }
}];

/**
 * Compute Token Cost — calcule cost_eur depuis les tokens LLM
 */
const data = $input.first().json;

const PRICING = {
  gemini: { prompt: 0.075 / 1_000_000, completion: 0.30 / 1_000_000 },
  mistral: { prompt: 0.10 / 1_000_000, completion: 0.30 / 1_000_000 },
  static: { prompt: 0, completion: 0 }
};

const pricing = PRICING[data.llm_provider] || PRICING.static;
const costEur = (data.llm_prompt_tokens || 0) * pricing.prompt
              + (data.llm_completion_tokens || 0) * pricing.completion;

return [{
  json: {
    ...data,
    token_cost_eur: costEur
  }
}];

/**
 * Compute Alert Level — détermine le niveau d'alerte basé sur le budget
 * (anomaly detection 7j déférée — à ajouter via 2 HTTP nodes Get Daily Avg / Get Today)
 */
const data = $input.first().json;

const usedBefore = data.ai_used_tokens || 0;
const justAdded = data.llm_total_tokens || 0;
const newTotal = usedBefore + justAdded;
const budget = data.ai_budget || 100000;
const newPercent = budget > 0 ? Math.round((newTotal / budget) * 100) : 0;

let alertLevel = 'none';
if (newPercent >= 100) alertLevel = 'critical';
else if (newPercent >= 95) alertLevel = 'warning';
else if (newPercent >= 80) alertLevel = 'info';

return [{
  json: {
    ...data,
    token_log_cost_eur: data.token_cost_eur || 0,
    token_log_new_total: newTotal,
    token_log_new_percent: newPercent,
    token_log_alert_level: alertLevel,
    token_log_is_anomaly: false,
    token_log_daily_avg: 0
  }
}];

/**
 * Build Tool Response v3 — groupe les slots par date quand scan_days > 1
 * pour que Gemini AI Final puisse proposer le 1er créneau dispo à coup sûr.
 * v3 : cap à 5 slots/jour max pour économiser les tokens (Gemini en proposera 2-3).
 */
const availItems = $('Check Availability').all() || [];
const validSlots = availItems.filter(it => it && it.json && it.json.slot_start);

let tool_response_data;
if (validSlots.length === 0) {
  tool_response_data = {
    days: [],
    count: 0,
    message: "Aucun créneau disponible pour la période demandée."
  };
} else {
  const timeFmt = new Intl.DateTimeFormat('fr-FR', {
    timeZone: 'Europe/Paris',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });
  const dayLabelFmt = new Intl.DateTimeFormat('fr-FR', {
    timeZone: 'Europe/Paris',
    weekday: 'long',
    day: 'numeric',
    month: 'long'
  });
  const dateKeyFmt = new Intl.DateTimeFormat('fr-CA', {
    timeZone: 'Europe/Paris',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  });

  // Regroupe les slots par date (clef = yyyy-mm-dd en tz Paris)
  const byDate = {};
  validSlots.forEach(it => {
    const d = new Date(it.json.slot_start);
    const dateKey = dateKeyFmt.format(d);
    if (!byDate[dateKey]) {
      byDate[dateKey] = {
        date: dateKey,
        day_label: dayLabelFmt.format(d),
        slots: []
      };
    }
    byDate[dateKey].slots.push({
      time: timeFmt.format(d),
      iso: it.json.slot_start,
      practitioner: it.json.practitioner_name,
      practitioner_id: it.json.practitioner_id
    });
  });

  const days = Object.values(byDate).sort((a, b) => a.date.localeCompare(b.date));

  // v3 : cap à 5 slots/jour max. Gemini en proposera 2-3 parmi ceux-ci.
  // Économise ~80% des tokens du call 2 (scan_days=14 passait à 11k tokens avant).
  // total_slots_on_day garde l'info réelle pour que Gemini sache qu'il y a plus si besoin.
  const MAX_SLOTS_PER_DAY = 5;
  days.forEach(day => {
    day.total_slots_on_day = day.slots.length;
    if (day.slots.length > MAX_SLOTS_PER_DAY) {
      day.slots = day.slots.slice(0, MAX_SLOTS_PER_DAY);
    }
  });

  tool_response_data = {
    days: days,
    count: validSlots.length,
    message: `${validSlots.length} créneau${validSlots.length > 1 ? 'x' : ''} disponible${validSlots.length > 1 ? 's' : ''} sur ${days.length} jour${days.length > 1 ? 's' : ''}.`
  };
}

const ctx = $('Parse Gemini Response').first().json;

return [{
  json: {
    ...ctx,
    tool_response_data: tool_response_data
  }
}];

/**
 * Parse Final Response — extrait le texte JSON de la 2e réponse Gemini
 * (celle qui a reçu le résultat du tool) et merge les tokens du 1er + 2e appel.
 *
 * Option D : Gemini function calling pattern.
 */
const geminiOutput = $input.first().json;
const candidate = geminiOutput.candidates?.[0];
const text = candidate?.content?.parts?.[0]?.text || '{}';
const usageMetadata = geminiOutput.usageMetadata || {};

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    response_text: text || "Désolé, je n'ai pas compris. Pouvez-vous reformuler ?",
    action: 'none',
    booking_data: {}
  };
}

const ctx = $('Build Tool Response').first().json;

const call1Prompt = ctx.gemini_call1_prompt_tokens || 0;
const call1Completion = ctx.gemini_call1_completion_tokens || 0;
const call2Prompt = usageMetadata.promptTokenCount || 0;
const call2Completion = usageMetadata.candidatesTokenCount || 0;

return [{
  json: {
    ...ctx,
    response_text: parsed.response_text,
    action: parsed.action || 'none',
    booking_data: parsed.booking_data || {},
    llm_provider: 'gemini',
    llm_model: 'gemini-2.5-flash-lite',
    llm_prompt_tokens: call1Prompt + call2Prompt,
    llm_completion_tokens: call1Completion + call2Completion,
    llm_total_tokens: call1Prompt + call1Completion + call2Prompt + call2Completion,
    llm_is_fallback: false,
    llm_error: null
  }
}];

/**
 * Sanitize Prompt Inputs v3 — Option D polish 6
 */

const MAX_NAME = 80;
const MAX_MESSAGE = 500;
const MAX_HISTORY = 2000;
const MAX_FIELD = 200;
const MAX_HISTORY_MESSAGES = 10;

function sanitize(s, maxLen) {
  if (!s) return '';
  s = String(s)
    .replace(/\b(system|assistant|admin)\s*:/gi, '[FILTERED]')
    .replace(/\b(tu\s+es|you\s+are)\s+(now|maintenant|désormais)/gi, '[FILTERED]')
    .replace(/\bACT\s+AS\b/gi, '[FILTERED]')
    .replace(/\bRÈGLES?\s*:/gi, '[FILTERED]')
    .replace(/\bINSTRUCTION[S]?\s*:/gi, '[FILTERED]');
  if (s.length > maxLen) s = s.substring(0, maxLen) + '…';
  return s;
}

const ctx = $('Build Context').first().json;

const packagesData = $('Check Client Packages').first()?.json || [];
const subscriptionsData = $('Check Client Subscriptions').first()?.json || [];
const nowIso = new Date().toISOString();

const packages = Array.isArray(packagesData) ? packagesData : [];
const subscriptions = Array.isArray(subscriptionsData) ? subscriptionsData : [];

const activePackages = packages.filter(cp => {
  if (!cp.package || !cp.package.is_active) return false;
  if (cp.expires_at && cp.expires_at < nowIso) return false;
  return true;
});

const activeSubscriptions = subscriptions;

let coverageSummary = 'aucun';
if (activePackages.length > 0 || activeSubscriptions.length > 0) {
  const parts = [];
  activePackages.forEach(cp => {
    parts.push(`Forfait "${cp.package.name}" (${cp.remaining_uses} séances restantes)`);
  });
  activeSubscriptions.forEach(sub => {
    parts.push(`Abonnement "${sub.name}" (actif)`);
  });
  coverageSummary = parts.join(', ');
}

// Services list depuis Load Services
let servicesList = 'Aucun service actif';
try {
  const servicesItems = $('Load Services').all() || [];
  const services = servicesItems
    .map(it => it && it.json ? it.json : null)
    .filter(s => s && s.name && s.duration_minutes);
  if (services.length > 0) {
    servicesList = services
      .map(s => {
        const price = s.price_cents ? `${(s.price_cents / 100).toFixed(0)}€` : '';
        return `${s.name} (${s.duration_minutes} min${price ? ', ' + price : ''})`;
      })
      .join(', ');
  }
} catch (e) {
  servicesList = 'Aucun service actif';
}

// Historique conversation depuis Load Conversation History
let conversationHistoryText = 'Première interaction';
let hasHistory = false;
try {
  const lchItems = $('Load Conversation History').all() || [];
  const messages = lchItems
    .map(it => it && it.json ? it.json : null)
    .filter(m => m && m.content && m.sender);
  if (messages.length > 0) {
    const msgs = messages
      .sort((a, b) => (a.created_at || '').localeCompare(b.created_at || ''))
      .slice(-MAX_HISTORY_MESSAGES);
    if (msgs.length > 0) {
      const rawHistory = msgs
        .map(m => {
          const role = m.sender === 'ai' ? 'IA' : 'Client';
          return `[${role}] ${m.content}`;
        })
        .join('\n');
      conversationHistoryText = JSON.stringify(rawHistory).slice(1, -1);
      hasHistory = true;
    }
  }
} catch (e) {
  conversationHistoryText = 'Première interaction';
}

const slotsText = 'Les créneaux sont vérifiés à la demande via la fonction get_available_slots.';

// Pré-calcul des dates de référence (Europe/Paris)
const tz = 'Europe/Paris';
const nowDt = DateTime.now().setZone(tz);
const nowFr = nowDt.setLocale('fr');
const todayWeekday = nowDt.weekday;

// Greeting selon l'heure locale Paris
const currentHour = nowDt.hour;
const greetingWord = (currentHour >= 18 || currentHour < 5) ? 'Bonsoir' : 'Bonjour';

// Détection intention booking : si la phrase contient un mot-clé booking ET un indice
// temporel, on force Gemini à appeler get_available_slots (mode ANY) pour éviter
// les hallucinations (Gemini Flash Lite ignore parfois la règle du prompt).
const msgLower = String(ctx.message_text || '').toLowerCase();
const bookingKeywords = /\b(rdv|rendez[-\s]?vous|créneau|creneau|dispo|disponibilit|réserver|reserver|réservation|coupe|barbe|coiffure|soin|service)\b/i;
const timeKeywords = /\b(demain|après[-\s]?demain|aujourd'hui|ce\s+soir|ce\s+matin|lundi|mardi|mercredi|jeudi|vendredi|samedi|dimanche|semaine|prochain|suivant|tot|tôt|rapidement|asap|avant|après)\b/i;
const hasBookingIntent = bookingKeywords.test(msgLower);
const hasTimeClue = timeKeywords.test(msgLower);
const shouldForceToolCall = hasBookingIntent && hasTimeClue;
const toolCallMode = shouldForceToolCall ? 'ANY' : 'AUTO';

function nextWeekday(targetIso) {
  const daysAhead = ((targetIso - todayWeekday + 7) % 7) || 7;
  return nowDt.plus({ days: daysAhead }).toFormat('yyyy-MM-dd');
}

const nextMondayIso = nextWeekday(1);
const weekAfterNextMondayDt = DateTime.fromISO(nextMondayIso, { zone: tz }).plus({ days: 7 });

const weekdayNames = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];
const openingHours = ctx.opening_hours || {};
let nextOpenDay = nowDt.plus({ days: 1 }).toFormat('yyyy-MM-dd');
for (let i = 1; i <= 14; i++) {
  const candidate = nowDt.plus({ days: i });
  const dayName = weekdayNames[candidate.weekday - 1];
  const dayConfig = openingHours[dayName];
  if (dayConfig && dayConfig.open) {
    nextOpenDay = candidate.toFormat('yyyy-MM-dd');
    break;
  }
}

const ref_dates = {
  today: nowDt.toFormat('yyyy-MM-dd'),
  today_label: nowFr.toFormat('cccc yyyy-MM-dd'),
  tomorrow: nowDt.plus({ days: 1 }).toFormat('yyyy-MM-dd'),
  day_after_tomorrow: nowDt.plus({ days: 2 }).toFormat('yyyy-MM-dd'),
  next_open_day: nextOpenDay,
  next_monday: nextMondayIso,
  next_tuesday: nextWeekday(2),
  next_wednesday: nextWeekday(3),
  next_thursday: nextWeekday(4),
  next_friday: nextWeekday(5),
  next_saturday: nextWeekday(6),
  next_sunday: nextWeekday(7),
  week_after_next_monday: weekAfterNextMondayDt.toFormat('yyyy-MM-dd'),
  week_after_next_tuesday: weekAfterNextMondayDt.plus({ days: 1 }).toFormat('yyyy-MM-dd'),
  week_after_next_wednesday: weekAfterNextMondayDt.plus({ days: 2 }).toFormat('yyyy-MM-dd'),
  week_after_next_thursday: weekAfterNextMondayDt.plus({ days: 3 }).toFormat('yyyy-MM-dd'),
  week_after_next_friday: weekAfterNextMondayDt.plus({ days: 4 }).toFormat('yyyy-MM-dd'),
  week_after_next_saturday: weekAfterNextMondayDt.plus({ days: 5 }).toFormat('yyyy-MM-dd')
};

let conversationIdFromRpc = null;
try {
  const ecOut = $('Ensure Conversation').first().json;
  if (ecOut && ecOut.id) {
    conversationIdFromRpc = ecOut.id;
  } else if (Array.isArray(ecOut) && ecOut.length > 0 && ecOut[0].id) {
    conversationIdFromRpc = ecOut[0].id;
  }
} catch (e) {}

return [{
  json: {
    ...ctx,
    safe_client_name: sanitize(ctx.client_name, MAX_NAME) || 'Inconnu',
    safe_message_text: sanitize(ctx.message_text, MAX_MESSAGE),
    safe_preferred_service: sanitize(ctx.preferred_service, MAX_FIELD) || 'aucun',
    safe_preferred_practitioner: sanitize(ctx.preferred_practitioner, MAX_FIELD) || 'aucun',
    safe_active_package: sanitize(coverageSummary, MAX_FIELD) || 'aucun',
    safe_conversation_history: sanitize(conversationHistoryText, MAX_HISTORY),
    safe_available_slots_text: slotsText,
    safe_services_list: servicesList,
    safe_greeting_word: greetingWord,
    safe_has_history: hasHistory,
    safe_tool_call_mode: toolCallMode,
    safe_loyalty_points: Number(ctx.loyalty_points) || 0,
    safe_cancellation_delay: Number(ctx.cancellation_delay_minutes) || 120,
    has_active_coverage: activePackages.length > 0 || activeSubscriptions.length > 0,
    ref_dates: ref_dates,
    conversation_id: conversationIdFromRpc
  }
}];

